import { Component, Element, h, Prop, State, Event, EventEmitter, Listen, Watch, Fragment } from '@stencil/core';
import { isStandaloneResultsListItemElement, StandaloneResultListSelectionMode, StandaloneResultsListItemElement } from './wdpr-standalone-results-list.model';
import { customTwMerge } from '../../utils/utils';
import { IconLibrarySize } from '../wdpr-icon-library/wdpr-icon-library.model';
import { RadialLabelPlacement, RadialLoaderSize } from '../wdpr-radial-loader/wdpr-radial-loader.model';
import { InlineMessageSize } from '../wdpr-inline-message/wdpr-inline-message.model';

@Component({
  tag: 'wdpr-standalone-results-list',
  shadow: true,
})
export class WdprStandaloneResultsList {
  @Element() el: HTMLWdprStandaloneResultsListElement;

  @State() _measuredMaxHeight: string | null = null;
  @State() _readyToShow: boolean = false;
  @State() _selectedValues: Set<string> = new Set();

  @Prop() mode: StandaloneResultListSelectionMode = 'single';
  @Prop() maxViewableItems: number | null = null;
  @Prop() showDivider: boolean = true;
  @Prop() isLoading: boolean = false;
  @Prop() loadingText: string = 'Loading...';
  @Prop() loaderSize: RadialLoaderSize = 'medium';
  @Prop() loaderLabelPlacement: RadialLabelPlacement = 'inline';
  @Prop() showLoaderLabel: boolean = true;
  @Prop() isEmpty: boolean = false;
  @Prop() emptyText: string = 'No results.';
  @Prop() emptyIcon: string = 'search';
  @Prop() emptyIconSize: IconLibrarySize = 'large';
  @Prop() errorOnLoad: boolean = false;
  @Prop() errorText: string = 'Failed to load items. Please try again.';
  @Prop() errorTextSize: InlineMessageSize = 'default';

  @Event() wdprSelectionChange: EventEmitter<{ selectedValues: string[] }>;

  @Watch('_selectedValues')
  updateSelectedValues() {
    this._syncSelectionItemsState();
  }

  @Watch('maxViewableItems')
  handleMaxViewableItemsChange() {
    requestAnimationFrame(() => {
      this._measureItemHeights();
    });
  }

  @Listen('wdprSelect', { capture: true })
  handleItemSelect(event: CustomEvent<{ value: string; selected: boolean }>) {
    event.stopPropagation();
    const {
      detail: { value, selected },
    } = event;
    this._updateSelectedValues(value, selected);
  }

  componentDidLoad() {
    requestAnimationFrame(() => {
      this._initAllItems();
      this._measureItemHeights();
    });
  }

  private _getAllListItems(): StandaloneResultsListItemElement[] {
    const slot = this.el.shadowRoot?.querySelector('slot');
    if (!slot) return [];

    const assigned = slot.assignedElements({ flatten: true }) as Element[];
    const allItems: StandaloneResultsListItemElement[] = [];

    for (const el of assigned) {
      if (el.tagName === 'WDPR-STANDALONE-RESULTS-LIST-GROUP') {
        const groupShadow = (el as HTMLWdprStandaloneResultsListGroupElement).shadowRoot;
        if (groupShadow) {
          const groupSlot = groupShadow.querySelector('slot');
          if (groupSlot) {
            const groupAssigned = (groupSlot as HTMLSlotElement).assignedElements({ flatten: true });
            allItems.push(...groupAssigned.filter(isStandaloneResultsListItemElement));
          }
        }
      } else if (isStandaloneResultsListItemElement(el as HTMLElement)) {
        allItems.push(el as StandaloneResultsListItemElement);
      }
    }

    return allItems;
  }

  private async _initAllItems() {
    const allItems = this._getAllListItems();

    if (allItems.length === 0) return;
    const lastItem = allItems[allItems.length - 1];

    const selectedSet = new Set<string>();
    for (const item of allItems) {
      if (!this.showDivider || item === lastItem) {
        if (typeof item.hideDivider === 'function') {
          await item.hideDivider();
        }
      }

      if (item.selected) {
        selectedSet.add(item.value);
      }

      item.mode = this.mode;
    }

    this._selectedValues = selectedSet;
  }

  private _updateSelectedValues(value: string, selected: boolean) {
    if (this.mode === 'single') {
      this._updateValuesFromSingleSelection(value, selected);
    }

    if (this.mode === 'multiple') {
      this._updateValuesFromMultipleSelection(value, selected);
    }

    this.wdprSelectionChange.emit({ selectedValues: Array.from(this._selectedValues) });
  }

  private _updateValuesFromSingleSelection(value: string, selected: boolean) {
    if (selected) {
      this._selectedValues = new Set([value]);
    } else {
      this._selectedValues = new Set();
    }
  }

  private _updateValuesFromMultipleSelection(value: string, selected: boolean) {
    const newSelectedValues = new Set(this._selectedValues);
    if (selected) {
      newSelectedValues.add(value);
    } else {
      newSelectedValues.delete(value);
    }
    this._selectedValues = newSelectedValues;
  }

  private _syncSelectionItemsState() {
    const items = this._getAllListItems();
    items.forEach(item => {
      item.selected = this._selectedValues.has(item.value);
    });
  }

  /**
   * Measures the height of the standalone result list and sets the max height for scrollable lists.
   * Calculates based on the number of visible items and their bounding rectangles.
   */
  private _measureItemHeights() {
    if (this.maxViewableItems == null || this.maxViewableItems <= 0) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const allListItems: HTMLElement[] = this._getAllListItems();

    const wrapper = this.el.shadowRoot?.querySelector('.wrapper');

    if (!wrapper || allListItems.length === 0) {
      this._readyToShow = true;

      return;
    }

    if (allListItems.length <= this.maxViewableItems) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const targetItem = allListItems[this.maxViewableItems - 1];
    const wrapperRect = wrapper.getBoundingClientRect();
    const itemRect = targetItem.getBoundingClientRect();

    let calculatedHeight = Math.ceil(itemRect.bottom - wrapperRect.top);

    // Add Wrapper Padding (if available)
    const style = window.getComputedStyle(wrapper);
    const paddingBottom = parseFloat(style.paddingBottom) || 0;
    calculatedHeight += paddingBottom;

    this._measuredMaxHeight = `${calculatedHeight}px`;
    this._readyToShow = true;
  }

  private _handleSlotChange = async () => {
    this._initAllItems();
    this._measureItemHeights();
  };

  private _renderContent() {
    const slot = this.el.shadowRoot?.querySelector('slot');
    let TagType = 'ul';

    if (slot) {
      const assigned = slot.assignedElements({ flatten: true }) as Element[];
      const onlyGroups = assigned.length > 0 && assigned.every(el => el.tagName === 'WDPR-STANDALONE-RESULTS-LIST-GROUP');

      TagType = onlyGroups ? 'div' : 'ul';
    }

    return (
      <TagType class="wrapper flex flex-col gap-y-100 p-200">
        <slot onSlotchange={this._handleSlotChange} />
      </TagType>
    );
  }

  private get _wrapperClasses() {
    return customTwMerge('overflow-y-auto', this._readyToShow ? 'visible' : 'invisible');
  }

  render() {
    const needsScrollbar = this._measuredMaxHeight !== null;

    return (
      <div class={this._wrapperClasses} style={{ height: this._measuredMaxHeight }}>
        {!this.isLoading && !this.errorOnLoad && !this.isEmpty && (
          <Fragment>
            {needsScrollbar ? (
              <wdpr-scrollbar orientation="vertical" size="small">
                {this._renderContent()}
              </wdpr-scrollbar>
            ) : (
              this._renderContent()
            )}
          </Fragment>
        )}

        {this.isLoading && this.loadingText && (
          <wdpr-surface-style variant="basic" customClass="elevation-xsmall-soft py-300 px-200 flex flex-col items-center justify-center">
            <wdpr-radial-loader label={this.loadingText} size={this.loaderSize} labelPlacement={this.loaderLabelPlacement} showLabel={this.showLoaderLabel} />
          </wdpr-surface-style>
        )}

        {!this.isLoading && this.isEmpty && this.emptyText && (
          <wdpr-surface-style variant="basic" customClass="elevation-xsmall-soft py-600 px-200">
            <div class="flex flex-col items-center justify-center gap-100 text-text-disabled">
              <wdpr-icon-library icon={this.emptyIcon} size={this.emptyIconSize} decorative />
              <p class="text-body-large text-text-disclaimer">{this.emptyText}</p>
            </div>
          </wdpr-surface-style>
        )}

        {!this.isLoading && this.errorOnLoad && this.errorText && (
          <wdpr-surface-style variant="basic" customClass="elevation-xsmall-soft py-600 px-200 flex flex-col items-center justify-center">
            <wdpr-inline-message variant="error" size={this.errorTextSize}>{this.errorText}</wdpr-inline-message>
          </wdpr-surface-style>
        )}
      </div>
    );
  }
}
