// Shared interface for all valid list items
export interface StandaloneResultsListItemElement extends HTMLElement {
  value: string;
  selected: boolean;
  disabled: boolean;
  mode: string;
  hideDivider?: () => Promise<void>;
}

export function isStandaloneResultsListItemElement(el: HTMLElement): el is StandaloneResultsListItemElement {
  return el.hasAttribute('data-standalone-results-list-item') && typeof (el as StandaloneResultsListItemElement).value === 'string' && 'selected' in el && 'mode' in el && 'disabled' in el;
}

export type StandaloneResultListSelectionMode = 'single' | 'multiple';
